Prolog:
sEnvironment = Upper(Trim(pEnvironment));
sDimensionName = Trim(pDimensionName);
sGroupName = Trim(pGroupName);
sAccess = Upper(Trim(pAccess));
sLogOnly = Upper(Trim(pLogOnly));
sLogToCube = Upper(Trim(pLogToCube));
sLogFile = Trim(pLogFile);
sUseBedrock = Upper(Trim(pUseBedrock));
sBedrockProcess = Trim(pBedrockProcess);
sStrictBedrock = Upper(Trim(pStrictBedrock));
sBedrockSecurityLevel = 'Read';
nBedrockReturn = ProcessExitNormal();
sBedrockStrictError = '0';
If(sUseBedrock @= ''); sUseBedrock = 'N'; EndIf;
If(sBedrockProcess @= ''); sBedrockProcess = '}bedrock.security.object.assign'; EndIf;
If(sStrictBedrock @= ''); sStrictBedrock = 'N'; EndIf;
If(sStrictBedrock @= 'Y'); sBedrockStrictError = '1'; EndIf;
If(sAccess @= 'WRITE');
  sBedrockSecurityLevel = 'Write';
ElseIf(sAccess @= 'ADMIN');
  sBedrockSecurityLevel = 'Admin';
ElseIf(sAccess @= 'NONE');
  sBedrockSecurityLevel = 'None';
EndIf;
If((sDimensionName @= '') % (sGroupName @= '')); ProcessBreak; EndIf;
If(CubeExists('}DimensionSecurity') = 0); ProcessBreak; EndIf;
sDimensionSecurityDim1 = TABDIM('}DimensionSecurity', 1);
sDimensionSecurityDim2 = TABDIM('}DimensionSecurity', 2);
If(sUseBedrock @= 'Y');
  If(ProcessExists(sBedrockProcess) = 1);
    ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'SET_DIMENSION_ACCESS', 'pObjectType', 'PROCESS', 'pObjectName', sBedrockProcess, 'pStatus', 'INFO', 'pMessage', 'Bedrock-backed dimension security mode is enabled. Group=' | sGroupName | '; expected=' | sAccess, 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
    nBedrockReturn = ExecuteProcess(sBedrockProcess, 'pGroup', sGroupName, 'pObjectType', 'Dimension', 'pObject', sDimensionName, 'pSecurityLevel', sBedrockSecurityLevel, 'pSecurityRefresh', 'No', 'pLogOutput', '0', 'pStrictErrorHandling', sBedrockStrictError);
    If((nBedrockReturn <> ProcessExitNormal()) & (sStrictBedrock @= 'Y')); ProcessBreak; EndIf;
  Else;
    ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'SET_DIMENSION_ACCESS', 'pObjectType', 'PROCESS', 'pObjectName', sBedrockProcess, 'pStatus', 'WARNING', 'pMessage', 'Requested Bedrock dimension-security process was not found. Existing IMF logging path remains active.', 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
    If(sStrictBedrock @= 'Y'); ProcessBreak; EndIf;
  EndIf;
EndIf;
If(sLogOnly @= 'N');
  If(sDimensionSecurityDim1 @= '}Groups');
    CellPutS(sAccess, '}DimensionSecurity', sGroupName, sDimensionName);
    sActualAccess = CellGetS('}DimensionSecurity', sGroupName, sDimensionName);
  Else;
    CellPutS(sAccess, '}DimensionSecurity', sDimensionName, sGroupName);
    sActualAccess = CellGetS('}DimensionSecurity', sDimensionName, sGroupName);
  EndIf;
  If(Upper(Trim(sActualAccess)) @= sAccess);
    ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'SET_DIMENSION_ACCESS', 'pObjectType', 'DIMENSION', 'pObjectName', sDimensionName, 'pStatus', 'OK', 'pMessage', 'Applied }DimensionSecurity. Group=' | sGroupName | '; expected=' | sAccess | '; actual=' | sActualAccess, 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
  Else;
    ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'SET_DIMENSION_ACCESS', 'pObjectType', 'DIMENSION', 'pObjectName', sDimensionName, 'pStatus', 'ERROR', 'pMessage', 'Native }DimensionSecurity write mismatch. Group=' | sGroupName | '; expected=' | sAccess | '; actual=' | sActualAccess, 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
    If(sStrictBedrock @= 'Y'); ProcessBreak; EndIf;
  EndIf;
Else;
  ExecuteProcess('IMF.P.Security.LogBootstrap', 'pEnvironment', sEnvironment, 'pAction', 'SET_DIMENSION_ACCESS', 'pObjectType', 'DIMENSION', 'pObjectName', sDimensionName, 'pStatus', 'INFO', 'pMessage', 'Log-only dimension assignment. Group=' | sGroupName | '; expected=' | sAccess, 'pLogToCube', sLogToCube, 'pLogFile', sLogFile);
EndIf;
